using Mirror;

public sealed class NetMirrorState
{
  private SyncDictionary<int, int> NetworkState = new SyncDictionary<int, int>();

  private void InitNetworkState()
  {
    NetworkState.Callback += OnNetworkStateChanged;
  }

  private void OnNetworkStateChanged(SyncDictionary<int, int>.Operation op, int key, int value) {}
}

using Mirror;

public sealed class GameMirrorState
{
  private SyncDictionary<int, int> GameplayState = new SyncDictionary<int, int>();

  private void InitGameplayState()
  {
    GameplayState.Callback += OnGameplayStateChanged;
  }

  private void OnGameplayStateChanged(SyncDictionary<int, int>.Operation op, int key, int value) {}
}

using Mirror;

public sealed class HealthMirrorState
{
  [SyncVar(hook = nameof(OnHealthChanged))]
  public int Health;

  private void OnHealthChanged(int oldValue, int newValue) {}
}
